// Delayed function call (2 seconds, non-looping)
FTimerHandle RespawnHandle;
GetWorldTimerManager().SetTimer(RespawnHandle, this, &AMyGameMode::RespawnPlayer, 2.0f, false);

// Repeating timer (every 0.5 seconds)
FTimerHandle DamageHandle;
GetWorldTimerManager().SetTimer(DamageHandle, this, &AMyTrap::ApplyDOT, 0.5f, true);

// Lambda timer
FTimerHandle LambdaHandle;
GetWorldTimerManager().SetTimer(LambdaHandle, [this]() {
    Health -= 10.f;
    if (Health <= 0.f) {
        GetWorldTimerManager().ClearTimer(LambdaHandle);
        Die();
    }
}, 1.0f, true);

// Cancel
GetWorldTimerManager().ClearTimer(DamageHandle);

// Check
if (GetWorldTimerManager().IsTimerActive(RespawnHandle)) {
    float Remaining = GetWorldTimerManager().GetTimerRemaining(RespawnHandle);
}

// Declare
DECLARE_DELEGATE_TwoParams(FOnDamageDealt, float, AActor*);

// In a class
FOnDamageDealt OnDamageDealt;

// Bind
OnDamageDealt.BindUObject(this, &AMyActor::HandleDamage);

// Or bind lambda
OnDamageDealt.BindLambda([](float Damage, AActor* Target) {
    UE_LOG(LogTemp, Log, TEXT("Dealt %f damage"), Damage);
});

// Call
OnDamageDealt.ExecuteIfBound(50.f, TargetActor);

// Declare
DECLARE_MULTICAST_DELEGATE_OneParam(FOnHealthChanged, float);

// In a class
FOnHealthChanged OnHealthChanged;

// Subscribe (multiple listeners)
FDelegateHandle UIHandle = OnHealthChanged.AddUObject(HealthBar, &UHealthBar::UpdateDisplay);
FDelegateHandle AIHandle = OnHealthChanged.AddUObject(AIController, &AAICtrl::OnTargetHealthChanged);

// Broadcast to all
OnHealthChanged.Broadcast(CurrentHealth);

// Unsubscribe one
OnHealthChanged.Remove(UIHandle);

// Unsubscribe all from a specific object
OnHealthChanged.RemoveAll(HealthBar);

// Declaration
DECLARE_DYNAMIC_MULTICAST_DELEGATE_TwoParams(FOnDeath, ACharacter*, DeadCharacter, AActor*, Killer);

UCLASS()
class AMyCharacter : public ACharacter {
    GENERATED_BODY()
public:
    // Bindable in Blueprint
    UPROPERTY(BlueprintAssignable, Category="Events")
    FOnDeath OnDeath;

    void Die(AActor* Killer) {
        OnDeath.Broadcast(this, Killer);
    }
};

// C++ binding with AddDynamic
void AMyGameMode::PostLogin(APlayerController* PC) {
    if (AMyCharacter* Char = Cast<AMyCharacter>(PC->GetPawn())) {
        Char->OnDeath.AddDynamic(this, &AMyGameMode::HandlePlayerDeath);
    }
}

